"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { LocalDB } from "@/lib/local-storage/db"
import { planRebalance, executePlannedTrades } from "@/lib/analysis/rebalancer"

export function RebalanceScheduler() {
  const [strategies, setStrategies] = useState<any[]>([])
  const [running, setRunning] = useState(false)
  const [autoRun, setAutoRun] = useState(() => {
    try {
      return localStorage.getItem('rebalance_auto_run') === '1'
    } catch (e) {
      return false
    }
  })

  const load = async () => {
    const s = await LocalDB.getStrategies()
    setStrategies(s || [])
  }

  useEffect(() => {
    load()
  }, [])

  useEffect(() => {
    if (!autoRun) return
    // run once on load if enabled
    (async () => {
      await runScheduledRebalances()
    })()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [autoRun])

  const isDueCalendar = (lastRunIso: string | undefined, frequency: string | undefined) => {
    if (!frequency) return true
    if (!lastRunIso) return true
    try {
      const last = new Date(lastRunIso)
      const now = new Date()
      if (frequency === 'monthly') return now.getMonth() !== last.getMonth() || now.getFullYear() !== last.getFullYear()
      if (frequency === 'quarterly') return Math.floor(now.getMonth()/3) !== Math.floor(last.getMonth()/3) || now.getFullYear() !== last.getFullYear()
      if (frequency === 'annually' || frequency === 'yearly') return now.getFullYear() !== last.getFullYear()
      return true
    } catch (e) {
      return true
    }
  }

  const runScheduledRebalances = async () => {
    setRunning(true)
    try {
      const s = await LocalDB.getStrategies()
      for (const strat of s) {
        if (!strat.rebalancing) continue
        const type = strat.rebalancing.type
        if (type === 'calendar') {
          const state = await LocalDB.getRebalanceState(strat.id)
          const lastRun = state?.last_run
          const freq = strat.rebalancing.frequency
          if (!isDueCalendar(lastRun, freq)) continue
          const planned = await planRebalance(strat, strat.rebalancing.threshold_percent || 2)
          if (planned && planned.length) {
            await executePlannedTrades(strat.manager_id || 'u-manager-1', planned)
            await LocalDB.setRebalanceState(strat.id, new Date().toISOString())
          } else {
            // still update last_run to avoid repeated empty runs
            await LocalDB.setRebalanceState(strat.id, new Date().toISOString())
          }
        } else if (type === 'threshold') {
          const planned = await planRebalance(strat, strat.rebalancing.threshold_percent || 2)
          if (planned && planned.length) {
            await executePlannedTrades(strat.manager_id || 'u-manager-1', planned)
            await LocalDB.setRebalanceState(strat.id, new Date().toISOString())
          }
        }
      }
      await load()
      alert('Scheduled rebalance run complete (demo)')
    } catch (err) {
      console.error(err)
      alert('Scheduled rebalance failed')
    } finally {
      setRunning(false)
    }
  }

  const toggleAuto = (v: boolean) => {
    setAutoRun(v)
    try { localStorage.setItem('rebalance_auto_run', v ? '1' : '0') } catch (e) {}
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Rebalance Scheduler (Demo)</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="flex items-center gap-2 mb-3">
          <Button onClick={runScheduledRebalances} disabled={running}>{running ? 'Running...' : 'Run Scheduled Rebalances'}</Button>
          <div className="ml-auto flex items-center gap-2">
            <label className="text-sm text-gray-600">Auto-run on load</label>
            <input type="checkbox" checked={autoRun} onChange={(e) => toggleAuto(e.target.checked)} />
          </div>
        </div>

        <div className="space-y-2">
          {strategies.filter(s => s.rebalancing).map((s) => (
            <div key={s.id} className="flex items-center justify-between border rounded p-2">
              <div>
                <div className="font-semibold">{s.name}</div>
                <div className="text-xs text-gray-500">{s.rebalancing?.type} {s.rebalancing?.threshold_percent ? `• ${s.rebalancing.threshold_percent}%` : ''} {s.rebalancing?.frequency ? `• ${s.rebalancing.frequency}` : ''}</div>
              </div>
              <div className="flex gap-2">
                <Button size="sm" onClick={async () => {
                  // run single strategy
                  const planned = await planRebalance(s, s.rebalancing?.threshold_percent || 2)
                  if (!planned || planned.length === 0) return alert('No trades required')
                  if (!confirm(`Execute ${planned.length} planned trades for ${s.name}?`)) return
                  await executePlannedTrades(s.manager_id || 'u-manager-1', planned)
                  await LocalDB.setRebalanceState(s.id, new Date().toISOString())
                  alert('Rebalance executed (demo)')
                }}>Run</Button>
              </div>
            </div>
          ))}
          {strategies.filter(s => s.rebalancing).length === 0 && <div className="text-sm text-gray-500">No strategies with rebalancing configured.</div>}
        </div>
      </CardContent>
    </Card>
  )
}
