import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Briefcase, DollarSign, TrendingUp } from "lucide-react"
import { useEffect, useState } from "react"
import { LocalDB } from "@/lib/local-storage/db"
import { computeAndCacheScores } from "./score-cache"

interface ManagerOverviewProps {
  managedFundsCount: number
  totalAUM: number
}

export function ManagerOverview({ managedFundsCount, totalAUM }: ManagerOverviewProps) {
  const [avgTopScore, setAvgTopScore] = useState<number | null>(null)

  useEffect(() => {
    let mounted = true
    const load = async () => {
      try {
        const secs = await LocalDB.getSecurities()
        if (!secs || secs.length === 0) return
        const scoreMap = await computeAndCacheScores(secs, async (s: any) => {
          // lazy import to avoid circularities
          const mod = await import("@/lib/analysis/scoring")
          return mod.computeScoreForSecurity(s)
        }, 30 * 1000)

        const scores = Object.values(scoreMap).sort((a, b) => b - a)
        const top = scores.slice(0, 5)
        const avg = top.length ? top.reduce((s, v) => s + v, 0) / top.length : 0
        if (mounted) setAvgTopScore(avg)
      } catch (e) {
        // ignore
      }
    }
    load()
    return () => {
      mounted = false
    }
  }, [])
  const formatCurrency = (value: number) => {
    const crores = value / 10000000
    return `₹${crores.toFixed(2)} Cr`
  }

  return (
    <div className="grid gap-4 md:grid-cols-3">
      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Managed Funds</CardTitle>
          <Briefcase className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{managedFundsCount}</div>
          <p className="mt-1 text-xs text-gray-500">Active mutual funds</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Total AUM</CardTitle>
          <DollarSign className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
          <div className="text-3xl font-bold">{formatCurrency(totalAUM)}</div>
          <p className="mt-1 text-xs text-gray-500">Assets under management</p>
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <CardTitle className="text-sm font-medium text-gray-600">Avg. Performance</CardTitle>
          <TrendingUp className="h-4 w-4 text-gray-400" />
        </CardHeader>
        <CardContent>
            <div className="text-3xl font-bold text-green-600">
              {avgTopScore !== null ? `${(avgTopScore * 100).toFixed(2)}%` : `-`}
            </div>
            <p className="mt-1 text-xs text-gray-500">Avg Top-5 Opportunity Score</p>
        </CardContent>
      </Card>
    </div>
  )
}
