"use client"

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { ArrowUp, ArrowDown, TrendingUp } from "lucide-react"
import { useEffect, useState } from "react"
import { detectMACrossover } from "@/lib/analysis/trends"
import { LocalDB } from "@/lib/local-storage/db"

interface Security {
  id: string
  symbol: string
  name: string
  current_price: number
  previous_close: number
  sector: string
}

interface MarketSnapshotProps {
  securities: Security[]
}

export function MarketSnapshot({ securities }: MarketSnapshotProps) {
  const [trends, setTrends] = useState<Record<string, string>>({})

  useEffect(() => {
    let mounted = true
    const loadTrends = async () => {
      try {
        const map: Record<string, string> = {}
        await Promise.all(
          securities.map(async (s) => {
            try {
              if ((s as any).fund_id) {
                const nav = await LocalDB.getNAVHistory((s as any).fund_id)
                const t = detectMACrossover(nav)
                map[s.id] = t.signal
              } else {
                map[s.id] = "neutral"
              }
            } catch (e) {
              map[s.id] = "neutral"
            }
          }),
        )

        if (!mounted) return
        setTrends(map)
      } catch (err) {
        console.error(err)
      }
    }

    if (securities && securities.length) loadTrends()

    return () => {
      mounted = false
    }
  }, [securities])

  const formatCurrency = (value: number) => {
    return `₹${value.toFixed(2)}`
  }

  const calculateChange = (current: number, previous: number) => {
    const change = current - previous
    const changePercent = (change / previous) * 100
    return { change, changePercent }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <TrendingUp className="h-5 w-5" />
          Market Snapshot
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        {securities.map((security) => {
          const { change, changePercent } = calculateChange(
            Number(security.current_price),
            Number(security.previous_close),
          )
          const isPositive = change >= 0

          return (
            <div key={security.id} className="rounded-lg border p-3">
              <div className="mb-2 flex items-start justify-between">
                <div>
                  <h4 className="font-semibold text-sm">{security.symbol}</h4>
                  <p className="text-xs text-gray-500">{security.sector}</p>
                </div>
                    <div className="flex items-center gap-2">
                      <Badge variant="outline" className="text-xs">
                        {security.sector}
                      </Badge>
                      <div>
                        {trends[security.id] === "bullish" && (
                          <span className="text-xs bg-green-100 text-green-800 px-2 py-0.5 rounded">Bullish</span>
                        )}
                        {trends[security.id] === "bearish" && (
                          <span className="text-xs bg-red-100 text-red-800 px-2 py-0.5 rounded">Bearish</span>
                        )}
                        {(!trends[security.id] || trends[security.id] === "neutral") && (
                          <span className="text-xs bg-gray-100 text-gray-800 px-2 py-0.5 rounded">Neutral</span>
                        )}
                      </div>
                    </div>
              </div>
              <div className="flex items-end justify-between">
                <div>
                  <p className="text-lg font-bold">{formatCurrency(Number(security.current_price))}</p>
                </div>
                <div
                  className={`flex items-center gap-1 text-sm font-medium ${isPositive ? "text-green-600" : "text-red-600"}`}
                >
                  {isPositive ? <ArrowUp className="h-3 w-3" /> : <ArrowDown className="h-3 w-3" />}
                  <span>{Math.abs(changePercent).toFixed(2)}%</span>
                </div>
              </div>
            </div>
          )
        })}
      </CardContent>
    </Card>
  )
}
