"use client"

import { useEffect, useState } from "react"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"
import { LocalDB } from "@/lib/local-storage/db"

interface AllocationRow {
  fund_id: string
  allocation_percent: number
}

interface StrategyBuilderProps {
  initial?: any
  managerId?: string
  onSaved?: (s: any) => void
  onCancel?: () => void
}

export function StrategyBuilder({ initial, managerId, onSaved, onCancel }: StrategyBuilderProps) {
  const [name, setName] = useState(initial?.name || "")
  const [allocations, setAllocations] = useState<AllocationRow[]>(initial?.fund_allocations || [])
  const [rebalancingType, setRebalancingType] = useState<string>(initial?.rebalancing?.type || "none")
  const [thresholdPercent, setThresholdPercent] = useState<number>(initial?.rebalancing?.threshold_percent || 2)
  const [frequency, setFrequency] = useState<string>(initial?.rebalancing?.frequency || "monthly")
  const [funds, setFunds] = useState<any[]>([])
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    let mounted = true
    const load = async () => {
      const f = await LocalDB.getFunds()
      if (mounted) setFunds(f)
    }
    load()
    return () => {
      mounted = false
    }
  }, [])

  const addRow = () => setAllocations((s) => [...s, { fund_id: funds[0]?.id || "", allocation_percent: 0 }])

  const updateRow = (idx: number, key: keyof AllocationRow, value: any) => {
    setAllocations((s) => s.map((r, i) => (i === idx ? { ...r, [key]: value } : r)))
  }

  const removeRow = (idx: number) => setAllocations((s) => s.filter((_, i) => i !== idx))

  const totalAllocation = () => allocations.reduce((sum, r) => sum + Number(r.allocation_percent || 0), 0)

  const save = async () => {
    if (!name) return alert("Please provide a strategy name")
    if (allocations.length === 0) return alert("Add at least one allocation")
    const total = totalAllocation()
    if (Math.round(total) !== 100) return alert("Allocations must sum to 100% (rounding ok)")

    setSaving(true)
    try {
      const rebalancing = rebalancingType === "none" ? undefined : { type: rebalancingType as any, threshold_percent: thresholdPercent, frequency }
      const payload = { name, fund_allocations: allocations, manager_id: managerId, rebalancing }
      let saved
      if (initial?.id) saved = await LocalDB.updateStrategy(initial.id, payload)
      else saved = await LocalDB.createStrategy(payload)
      if (onSaved) onSaved(saved)
    } catch (err) {
      console.error(err)
      alert("Failed to save strategy")
    } finally {
      setSaving(false)
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>{initial?.id ? "Edit Strategy" : "New Strategy"}</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="mb-3">
          <label className="block text-sm text-gray-700 mb-1">Name</label>
          <Input value={name} onChange={(e: any) => setName(e.target.value)} />
        </div>

        <div className="space-y-2">
          {allocations.map((row, idx) => (
            <div key={idx} className="flex gap-2 items-center">
              <select className="flex-1 border p-2 rounded" value={row.fund_id} onChange={(e) => updateRow(idx, "fund_id", e.target.value)}>
                {funds.map((f) => (
                  <option key={f.id} value={f.id}>
                    {f.fund_name}
                  </option>
                ))}
              </select>
              <input className="w-24 border p-2 rounded" type="number" value={row.allocation_percent} onChange={(e) => updateRow(idx, "allocation_percent", Number(e.target.value))} />
              <button className="px-2 py-1 text-sm text-red-600" onClick={() => removeRow(idx)}>Remove</button>
            </div>
          ))}
        </div>

        <div className="mt-3 flex items-center gap-2">
          <button className="px-3 py-1 bg-gray-100 rounded" onClick={addRow}>Add Allocation</button>
          <div className="text-sm text-gray-600">Total: {totalAllocation()}%</div>
        </div>

        <div className="mt-4 border-t pt-3">
          <div className="mb-2 text-sm font-semibold">Rebalancing</div>
          <div className="flex items-center gap-2">
            <label className="text-sm">Type</label>
            <select value={rebalancingType} onChange={(e) => setRebalancingType(e.target.value)} className="border p-1 rounded">
              <option value="none">None</option>
              <option value="threshold">Threshold</option>
              <option value="calendar">Calendar</option>
            </select>
          </div>

          {rebalancingType === "threshold" && (
            <div className="mt-2">
              <label className="block text-sm text-gray-700">Threshold Percent</label>
              <Input type="number" value={thresholdPercent} onChange={(e: any) => setThresholdPercent(Number(e.target.value))} />
            </div>
          )}

          {rebalancingType === "calendar" && (
            <div className="mt-2">
              <label className="block text-sm text-gray-700">Frequency</label>
              <select className="border p-1 rounded" value={frequency} onChange={(e) => setFrequency(e.target.value)}>
                <option value="monthly">Monthly</option>
                <option value="quarterly">Quarterly</option>
                <option value="annually">Annually</option>
              </select>
            </div>
          )}
        </div>

        <div className="mt-4 flex gap-2">
          <Button onClick={save} disabled={saving}>{saving ? "Saving..." : "Save Strategy"}</Button>
          <button className="px-3 py-1 bg-gray-100 rounded" onClick={() => onCancel && onCancel()}>Cancel</button>
        </div>
      </CardContent>
    </Card>
  )
}
